import httpx, os, json

WEIBO_HOT_URL = 'https://weibo.com/ajax/side/hotSearch'
topics = []

try:
    r = httpx.get(WEIBO_HOT_URL, timeout=10, headers={'User-Agent': 'Mozilla/5.0'})
    data = r.json()
    realtime = data.get('data', {}).get('realtime', [])[:10]
    for item in realtime:
        topics.append({'source': 'weibo', 'keyword': item.get('word', ''), 'heat': item.get('num', 0), 'icon': item.get('icon_desc', '')})
except Exception as e:
    try:
        import feedparser
        feed = feedparser.parse('https://top.baidu.com/board?platform=wise&sa=pcindex_entry')
        for entry in feed.entries[:10]:
            topics.append({'source': 'baidu', 'keyword': entry.title, 'heat': 0, 'icon': ''})
    except:
        topics.append({'source': 'fallback', 'keyword': 'AI人工智能', 'heat': 9999, 'icon': '爆'})

topics.sort(key=lambda x: x['heat'], reverse=True)
selected = topics[0] if topics else {'keyword': 'AI最新进展', 'source': 'fallback', 'heat': 0, 'icon': ''}

return [{'json': {'topics': topics, 'selected': selected}}]

import httpx, os, json, time, uuid, base64
from pathlib import Path

COMFYUI_URL = os.environ.get('COMFYUI_URL', 'http://host.docker.internal:8188')
VIDEO_DIR   = os.environ.get('SAU_VIDEO_DIR', '/data/videos')
Path(VIDEO_DIR).mkdir(parents=True, exist_ok=True)

video_prompt    = $json['video_prompt']
negative_prompt = $json.get('negative_prompt', 'cartoon, childish, ugly, blurry, watermark, nsfw')
title           = $json['title']
client_id       = str(uuid.uuid4())

# ── LTX-Video 2.3 Distilled + Single-Stage API Workflow ──────────────────────
# 适配 llm-02: 16core / 64G RAM / RTX 4090 24GB
# 模型文件: ltx-video-2b-v0.9.1-fp8.safetensors (Distilled FP8, ~23GB)
# 文本编码: t5xxl_fp16.safetensors
# 分辨率: 768x1280 (竖版9:16), 97帧 @24fps ≈ 4秒视频
# ─────────────────────────────────────────────────────────────────────────────
COMFY_WORKFLOW = {
    "1": {
        "class_type": "CheckpointLoaderSimple",
        "inputs": {
            "ckpt_name": "ltx-video-2b-v0.9.1-fp8.safetensors"
        }
    },
    "2": {
        "class_type": "CLIPLoader",
        "inputs": {
            "clip_name": "t5xxl_fp16.safetensors",
            "type": "ltxv",
            "device": "default"
        }
    },
    "3": {
        "class_type": "CLIPTextEncode",
        "inputs": {
            "clip": ["2", 0],
            "text": video_prompt
        }
    },
    "4": {
        "class_type": "CLIPTextEncode",
        "inputs": {
            "clip": ["2", 0],
            "text": negative_prompt
        }
    },
    "5": {
        "class_type": "LTXVConditioning",
        "inputs": {
            "positive": ["3", 0],
            "negative": ["4", 0],
            "frame_rate": 24.0
        }
    },
    "6": {
        "class_type": "EmptyLTXVLatentVideo",
        "inputs": {
            "width": 768,
            "height": 1280,
            "length": 97,
            "batch_size": 1
        }
    },
    "7": {
        "class_type": "LTXVScheduler",
        "inputs": {
            "latent": ["6", 0],
            "steps": 15,
            "max_shift": 2.05,
            "base_shift": 0.95,
            "stretch": True,
            "terminal": 0.1
        }
    },
    "8": {
        "class_type": "KSamplerSelect",
        "inputs": {
            "sampler_name": "euler"
        }
    },
    "9": {
        "class_type": "RandomNoise",
        "inputs": {
            "noise_seed": int(time.time()) % 2147483647
        }
    },
    "10": {
        "class_type": "CFGGuider",
        "inputs": {
            "model": ["1", 0],
            "positive": ["5", 0],
            "negative": ["5", 1],
            "cfg": 3.5
        }
    },
    "11": {
        "class_type": "SamplerCustomAdvanced",
        "inputs": {
            "noise": ["9", 0],
            "guider": ["10", 0],
            "sampler": ["8", 0],
            "sigmas": ["7", 0],
            "latent_image": ["6", 0]
        }
    },
    "12": {
        "class_type": "VAEDecode",
        "inputs": {
            "samples": ["11", 0],
            "vae": ["1", 2]
        }
    },
    "13": {
        "class_type": "VHS_VideoCombine",
        "inputs": {
            "images": ["12", 0],
            "frame_rate": 24,
            "loop_count": 0,
            "filename_prefix": "vidpipe",
            "format": "video/mp4",
            "pingpong": False,
            "save_output": True
        }
    }
}

# 提交 workflow 到 ComfyUI
r = httpx.post(f'{COMFYUI_URL}/prompt', json={'prompt': COMFY_WORKFLOW, 'client_id': client_id}, timeout=30)
r.raise_for_status()
prompt_id = r.json()['prompt_id']

# 轮询等待生成完成（LTX 2.3 Distilled 在 4090 上约 90-180 秒）
output_file = None
for _ in range(120):  # 最多等 10 分钟
    time.sleep(5)
    try:
        history = httpx.get(f'{COMFYUI_URL}/history/{prompt_id}', timeout=10).json()
    except Exception:
        continue
    if prompt_id not in history:
        continue
    node_outputs = history[prompt_id].get('outputs', {})
    for node_id, node_output in node_outputs.items():
        # VHS_VideoCombine 输出在 'gifs' 字段
        for key in ('gifs', 'videos', 'images'):
            if key not in node_output:
                continue
            file_info = node_output[key][0]
            params = {'filename': file_info['filename'], 'subfolder': file_info.get('subfolder', ''), 'type': 'output'}
            file_resp = httpx.get(f'{COMFYUI_URL}/view', params=params, timeout=60)
            safe_title = ''.join(c for c in title if c.isalnum() or c in '_ ')[:30]
            ext = 'mp4' if key in ('gifs', 'videos') else 'png'
            output_file = f'{VIDEO_DIR}/{safe_title}_{prompt_id[:8]}.{ext}'
            with open(output_file, 'wb') as f:
                f.write(file_resp.content)
            break
        if output_file:
            break
    if output_file:
        break

if not output_file:
    raise Exception(f'ComfyUI 生成超时或失败，prompt_id={prompt_id}')

return [{'json': {**$json, 'video_path': output_file, 'prompt_id': prompt_id}}]
